        # SAT verifica con ultimos 8 chars del UUID
        fe = uuid_val.replace("-", "")[-8:]
        query = urlencode({
            "id": uuid_val,
            "re": rfc_emisor,
            "rr": rfc_receptor,
            "tt": total,
            "fe": fe,
        })
        url = f"{SAT_VERIFY_URL}?{query}"
        return {
            "success": True,
            "verify_url": url,
            "uuid": uuid_val,
            "estado": "Vigente",  # Em produção, fazer GET e parsear HTML
        }

